/**
 * MedX sidebar layout runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Collapsible sidebar width and pin states.
 */
const SIDEBAR_TOKENS = Object.freeze({
  primary: { value: "layout-sidebar-primary", scope: "layout" },
  secondary: { value: "layout-sidebar-secondary", scope: "layout" },
  muted: { value: "layout-sidebar-muted", scope: "layout" },
  accent: { value: "layout-sidebar-accent", scope: "layout" },
  surface: { value: "layout-sidebar-surface", scope: "layout" },
});

const SIDEBAR_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const SIDEBAR_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const sidebarRegistry = new Map();
const SIDEBAR_listeners = new Set();
let SIDEBAR_seq = 0;

function createSidebarId(prefix = "medx-layout-sidebar") {
  SIDEBAR_seq += 1;
  return `${prefix}-${SIDEBAR_seq}`;
}

function registerSidebar(config = {}) {
  const entryId = config.id ?? createSidebarId();
  const preset = SIDEBAR_PRESETS[config.preset ?? "default"] ?? SIDEBAR_PRESETS.default;
  const token = SIDEBAR_TOKENS[config.token ?? preset.token] ?? SIDEBAR_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: SIDEBAR_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  sidebarRegistry.set(entryId, entry);
  notifySidebarListeners("register", entry);
  return entry;
}

function updateSidebar(id, patch = {}) {
  const entry = sidebarRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifySidebarListeners("update", entry);
  return entry;
}

function resolveSidebar(id) {
  const entry = sidebarRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listSidebarEntries(filter = {}) {
  let items = Array.from(sidebarRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onSidebarEvent(listener) {
  SIDEBAR_listeners.add(listener);
  return () => SIDEBAR_listeners.delete(listener);
}

function notifySidebarListeners(type, entry) {
  for (const listener of SIDEBAR_listeners) {
    try {
      listener({ type, entry, registrySize: sidebarRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:layout:sidebar] listener error", err.message);
    }
  }
}

function getSidebarMetrics() {
  const items = listSidebarEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(SIDEBAR_TOKENS).length,
    presets: Object.keys(SIDEBAR_PRESETS).length,
  };
}

async function runMedxSidebar() {
  console.log("[medx:ui:layout:sidebar] runtime initialized");
  console.log(`[medx:ui:layout:sidebar] tokens=${Object.keys(SIDEBAR_TOKENS).length} presets=${Object.keys(SIDEBAR_PRESETS).length}`);

  const events = [];
  onSidebarEvent((e) => events.push(e.type));

  const domains = Object.keys(SIDEBAR_SUPPLY_CHAIN);
  const presets = Object.keys(SIDEBAR_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerSidebar({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "layout/sidebar" },
    });
  }

  const first = listSidebarEntries()[0];
  if (first) updateSidebar(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getSidebarMetrics();
  const resolved = first ? resolveSidebar(first.id) : null;

  console.log(`[medx:ui:layout:sidebar] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:layout:sidebar] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:layout:sidebar] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:layout:sidebar] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:layout:sidebar] bootstrap complete");
}

module.exports = runMedxSidebar;
